import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface PriceTrend {
  day: string;
  price: number;
}

interface GasPriceData {
  location: string;
  averagePrice: number;
  cheapestNearby: {
    station: string;
    price: number;
    distance: string;
  };
  priceTrend: PriceTrend[];
}

export default function Widget() {
  const gasPriceData = response.data as GasPriceData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#1976D2', mb: 0.5 }}>
              {gasPriceData.location}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Average Price: ${gasPriceData.averagePrice.toFixed(2)}
            </Typography>
          </Box>

          <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ bgcolor: '#F5F7FA', p: 1.5, borderRadius: 1 }}>
            <Typography variant="body2" fontWeight={500}>
              Cheapest Nearby:
            </Typography>
            <Box textAlign="right">
              <Typography variant="body2" fontWeight={600} sx={{ color: '#FF5722' }}>
                {gasPriceData.cheapestNearby.station}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                ${gasPriceData.cheapestNearby.price.toFixed(2)} - {gasPriceData.cheapestNearby.distance}
              </Typography>
            </Box>
          </Stack>

          <Box sx={{ width: '100%', height: 120 }}>
            <LineChart
              series={[
                {
                  data: gasPriceData.priceTrend.map((trend) => trend.price),
                  color: '#FFC107',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: gasPriceData.priceTrend.map((trend) => trend.day),
                  hide: false,
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
